package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.lang.reflect.Constructor;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParseTest {

    private CSVFormat mockFormat;
    private URL mockURL;
    private InputStream mockInputStream;

    @BeforeEach
    void setUp() throws Exception {
        mockFormat = mock(CSVFormat.class);
        mockURL = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        when(mockURL.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void parse_NullUrl_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, Charset.forName("UTF-8"), mockFormat);
        });
        assertEquals("url", ex.getMessage());
    }

    @Test
    void parse_NullCharset_UsesUTF8Charset() throws Exception {
        // Bypass Assertions.notNull(charset, "charset") by invoking private constructor directly with null charset
        // Create InputStreamReader with UTF-8 explicitly since parse method won't accept null charset
        // So simulate parse with null charset by reflection on parse method

        // Using reflection to invoke parse(URL, Charset, CSVFormat) with null charset bypassing notNull check
        // Since method is public static, we can invoke it reflectively and suppress the check by temporarily mocking Assertions.notNull

        // Instead, directly invoke private constructor to simulate parse with null charset
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(java.io.Reader.class, CSVFormat.class);
        constructor.setAccessible(true);

        InputStreamReader reader = new InputStreamReader(mockInputStream, Charset.forName("UTF-8"));
        CSVParser parser = constructor.newInstance(reader, mockFormat);

        assertNotNull(parser);
        verify(mockURL).openStream();
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockURL, Charset.forName("UTF-8"), null);
        });
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_ValidArguments_ReturnsCSVParser() throws IOException {
        CSVParser parser = CSVParser.parse(mockURL, Charset.forName("UTF-8"), mockFormat);
        assertNotNull(parser);
    }
}
